public struct X11ProbeInput {
    public var x11AdapterPath: String?
    public var display: String?
    public var xauthPresent: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(x11AdapterPath: String?, display: String?, xauthPresent: Bool) {
        self.x11AdapterPath = x11AdapterPath
        self.display = display
        self.xauthPresent = xauthPresent
    }
}

#if compiler(>=6)
extension X11ProbeInput: Sendable {}
#endif


extension X11ProbeInput: Equatable, Hashable {
    public static func ==(lhs: X11ProbeInput, rhs: X11ProbeInput) -> Bool {
        if lhs.x11AdapterPath != rhs.x11AdapterPath {
            return false
        }
        if lhs.display != rhs.display {
            return false
        }
        if lhs.xauthPresent != rhs.xauthPresent {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(x11AdapterPath)
        hasher.combine(display)
        hasher.combine(xauthPresent)
    }
}



#if swift(>=5.8)
