                display: FfiConverterOptionString.read(from: &buf),
                xauthPresent: FfiConverterBool.read(from: &buf)
        )
    }

    public static func write(_ value: X11ProbeInput, into buf: inout [UInt8]) {
        FfiConverterOptionString.write(value.x11AdapterPath, into: &buf)
        FfiConverterOptionString.write(value.display, into: &buf)
        FfiConverterBool.write(value.xauthPresent, into: &buf)
    }
